/// A case transformation that can be applied to a grapheme cluster returned
/// by [`Str::first`] and [`Str::last`].
#[derive(Debug, Copy, Clone, Eq, PartialEq, Hash, Cast)]
pub enum StrCase {
    /// Convert the grapheme cluster to uppercase.
    Upper,
    /// Convert the grapheme cluster to lowercase.
    Lower,
    /// Convert the grapheme cluster to title case: The first scalar value is
    /// uppercased, the rest are lowercased.
    Title,
}

/// Applies an optional case transformation to a grapheme cluster.
fn apply_case(grapheme: &str, case: Option<StrCase>) -> Str {
    match case {
        Some(StrCase::Upper) => grapheme.to_uppercase().into(),
        Some(StrCase::Lower) => grapheme.to_lowercase().into(),
        Some(StrCase::Title) => {
            let mut chars = grapheme.chars();
            let Some(first) = chars.next() else { return grapheme.into() };
            let mut result: String = first.to_uppercase().collect();
            result.extend(chars.flat_map(char::to_lowercase));
            result.into()
        }
        None => grapheme.into(),
    }
}

